380	// Helper functions for working directory-based operations
381	func extractUpdateOptions(cmd *cobra.Command, args []string) (*UpdateOptions, error) {
382		opts := &UpdateOptions{}
383	
384		// Extract flags
385		opts.Check, _ = cmd.Flags().GetBool("check")
386		opts.Force, _ = cmd.Flags().GetBool("force")
387		opts.Reset, _ = cmd.Flags().GetBool("reset")
388		opts.Sync, _ = cmd.Flags().GetBool("sync")
389		opts.Strategy, _ = cmd.Flags().GetString("strategy")
390		opts.Backup, _ = cmd.Flags().GetBool("backup")
391		opts.Interactive, _ = cmd.Flags().GetBool("interactive")
392		opts.Abort, _ = cmd.Flags().GetBool("abort")
393		opts.DryRun, _ = cmd.Flags().GetBool("dry-run")
394		opts.DiscardLocal, _ = cmd.Flags().GetBool("discard-local")
395		opts.Global, _ = cmd.Flags().GetBool("global")
396	
397		// Handle mine/theirs flags by converting to strategy
398		updateMine, _ := cmd.Flags().GetBool("mine")
399		updateTheirs, _ := cmd.Flags().GetBool("theirs")
400	
401		if updateMine && updateTheirs {
402			return nil, fmt.Errorf("cannot use both --mine and --theirs flags")
403		}
404		if updateMine {
405			opts.Strategy = "ours"
406		}
407		if updateTheirs {
408			opts.Strategy = "theirs"
409		}
410	
411		// Check for selective update
412		if len(args) > 0 {
413			opts.Resource = args[0]
414		}
415	
416		return opts, nil
417	}
