34	// runDoctor implements the doctor command logic
35	func (f *CommandFactory) runDoctor(cmd *cobra.Command, args []string) error {
36		pathsStr, _ := cmd.Flags().GetString("paths")
37		if pathsStr != "" {
38			return f.runDoctorScoped(strings.Fields(pathsStr))
39		}
40	
41		verbose, _ := cmd.Flags().GetBool("verbose")
42		applyHousekeeping, _ := cmd.Flags().GetBool("apply")
43		fix, _ := cmd.Flags().GetBool("fix")
44	
45		fmt.Println("🩺 DDx Installation Diagnostics")
46		fmt.Println("=====================================")
47		fmt.Println()
48	
49		var issues []DiagnosticIssue
50		allGood := true
51		auditPlugins, _ := cmd.Flags().GetBool("plugins")
52	
53		// Check 1: DDX Binary Executable and Install Location
54		fmt.Print("✓ Checking DDX Binary... ")
55		executable, err := os.Executable()
56		if err != nil {
57			fmt.Println("❌ Cannot determine executable location")
58			allGood = false
59		} else {
60			fmt.Printf("✅ DDX Binary Executable (%s)\n", executable)
61			if locationIssues := checkBinaryInstallLocation(executable); len(locationIssues) > 0 {
62				for _, issue := range locationIssues {
63					fmt.Printf("   ⚠️  %s\n", issue.Description)
64					for _, r := range issue.Remediation {
65						fmt.Printf("   💡 %s\n", r)
