499	// categorizeStagedPaths maps each path to a DDx check category.
500	// Returns a set of category names ("config", "resource") that apply to the
501	// given path list. Unrecognised paths produce no category.
502	func categorizeStagedPaths(paths []string) map[string]bool {
503		cats := make(map[string]bool)
504		resourcePrefixes := []string{"templates/", "patterns/", "prompts/"}
505		for _, p := range paths {
506			p = strings.TrimSpace(p)
507			if p == "" {
508				continue
509			}
510			if p == ".ddx.yml" || strings.HasSuffix(p, "/.ddx.yml") || filepath.Base(p) == ".ddx.yml" {
511				cats["config"] = true
512			}
513			for _, prefix := range resourcePrefixes {
514				if strings.HasPrefix(p, prefix) || strings.Contains(p, "/"+prefix) {
515					cats["resource"] = true
516				}
517			}
518		}
519		return cats
520	}
