659		defer cancel()
660	
661		output, err := exec.CommandContext(ctx, path, "--version").CombinedOutput()
662		version := strings.TrimSpace(string(output))
663		if err != nil {
664			desc := fmt.Sprintf("Vale prose checker did not report a supported version; expected %q", supportedValeVersion)
665			if version != "" {
666				desc += fmt.Sprintf("; got %q", version)
667			}
668			desc += fmt.Sprintf("; error: %v", err)
669			return proseCheckerStatus{
670				Path:    path,
671				Version: version,
672				Issue:   proseCheckerIssue(desc),
673			}
674		}
675		if version != supportedValeVersion {
676			if version == "" {
677				version = "<empty>"
678			}
679			return proseCheckerStatus{
680				Path:    path,
681				Version: version,
682				Issue: proseCheckerIssue(
683					fmt.Sprintf("Unsupported Vale prose checker version %q; expected %q", version, supportedValeVersion),
684				),
685			}
686		}
687	
688		return proseCheckerStatus{
689			Path:    path,
690			Version: version,
691		}
692	}
