875			}
876	
877			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
878			name := filepath.Base(dst)
879			fmt.Printf("✓ Checking %s launcher... ", name)
880	
881			li, err := os.Lstat(dst)
882			if os.IsNotExist(err) {
883				fmt.Printf("❌ MISSING (%s not found, run: ddx install %s)\n", dst, pkg.Name)
884				continue
885			}
886			if err != nil {
887				fmt.Printf("❌ error: %v\n", err)
888				continue
889			}
890	
891			if li.Mode()&os.ModeSymlink != 0 {
892				target, _ := os.Readlink(dst)
893				if verbose {
894					fmt.Printf("✅ OK (developer symlink → %s)\n", target)
895				} else {
896					fmt.Println("✅ OK (developer symlink)")
897				}
898				continue
899			}
900	
901			// Regular file — check it's executable.
902			if li.Mode()&0111 != 0 {
903				fmt.Printf("✅ OK (%s)\n", dst)
904			} else {
905				fmt.Printf("⚠️  not executable (run: chmod +x %s)\n", dst)
