910	// checkInstalledPlugins audits installed plugin roots and manifests.
911	func checkInstalledPlugins(verbose bool) []DiagnosticIssue {
912		state, err := registry.LoadState()
913		if err != nil || len(state.Installed) == 0 {
914			return nil
915		}
916	
917		reg := registry.BuiltinRegistry()
918		var issues []DiagnosticIssue
919	
920		for _, entry := range state.Installed {
921			fallback, _ := reg.Find(entry.Name)
922			entryType := entry.Type
923			if entryType == "" && fallback != nil {
924				entryType = fallback.Type
925			}
926			if entryType == "" && !looksLikePluginInstall(entry) {
927				continue
928			}
929			switch entryType {
930			case registry.PackageTypePlugin, registry.PackageTypeWorkflow:
931			case "":
932			default:
933				continue
934			}
935			for _, issue := range registry.AuditInstalledEntry(entry, fallback) {
936				diag := DiagnosticIssue{
937					Type:        "plugin_validation",
938					Description: issue.Error(),
939					Remediation: []string{
940						"Check package.yaml, skill directories, and installed symlinks for the path shown above",
941						"Reinstall the package after fixing the source tree or manifest",
942					},
943					SystemInfo: map[string]string{
944						"plugin": entry.Name,
945					},
946				}
947				if verbose {
948					diag.SystemInfo["source"] = entry.Source
949				}
950				issues = append(issues, diag)
951			}
952		}
953	
954		return issues
955	}
