57	// CommandFactory method - CLI interface layer
58	func (f *CommandFactory) runUpdate(cmd *cobra.Command, args []string) error {
59		// Extract flags to options struct
60		opts, err := extractUpdateOptions(cmd, args)
61		if err != nil {
62			return err
63		}
64	
65		// --global updates only the machine-wide plugin tree.
66		if opts.Global {
67			result, err := performGlobalUpdate(opts)
68			if err != nil {
69				return err
70			}
71			return displayUpdateResult(cmd, result, opts)
72		}
73	
74		// Call pure business logic
75		result, err := performUpdate(f.WorkingDir, opts)
76		if err != nil {
77			return err
78		}
79	
80		// Handle output formatting
81		return displayUpdateResult(cmd, result, opts)
82	}
