84	// isUpdateTargetDirty returns true when filePath exists, is tracked by git,
85	// and has uncommitted changes (staged or unstaged). Untracked files return false.
86	// Returns false on any error (git unavailable, not a repo, etc.).
87	func isUpdateTargetDirty(workingDir, filePath string) bool {
88		abs := filePath
89		if !filepath.IsAbs(abs) {
90			abs = filepath.Join(workingDir, filePath)
91		}
92		if _, err := os.Stat(abs); os.IsNotExist(err) {
93			return false
94		}
95	
96		rel, err := filepath.Rel(workingDir, abs)
97		if err != nil {
98			rel = filePath
99		}
100	
101		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
102		defer cancel()
103		cmd := gitpkg.Command(ctx, workingDir, "status", "--porcelain", "--", rel)
104		out, err := cmd.Output()
105		if err != nil {
106			return false
107		}
108		for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
109			if len(line) < 2 {
110				continue
111			}
112			// XY: X=index status, Y=worktree status. "??" = untracked — skip.
113			if line[:2] != "??" {
114				return true
115			}
116		}
117		return false
118	}
