143	// collectDirtyUpdateTargets returns absolute paths of files that would be
144	// overwritten by ddx update and currently have uncommitted git changes.
145	// Returns nil, nil when the working dir is not a git repository.
146	func collectDirtyUpdateTargets(workingDir string) ([]string, error) {
147		if !gitpkg.IsRepository(workingDir) {
148			return nil, nil
149		}
150	
151		var candidates []string
152		candidates = append(candidates, enumerateSkillUpdateTargets(workingDir)...)
153	
154		state, err := registry.LoadState()
155		if err == nil {
156			for _, entry := range state.Installed {
157				for _, f := range entry.Files {
158					expanded := registry.ExpandHome(f)
159					if !filepath.IsAbs(expanded) {
160						expanded = filepath.Join(workingDir, expanded)
161					}
162					candidates = append(candidates, expanded)
163				}
164			}
165		}
166	
167		var dirty []string
168		for _, c := range candidates {
169			if isUpdateTargetDirty(workingDir, c) {
170				dirty = append(dirty, c)
171			}
172		}
173		return dirty, nil
174	}
