296	// performGlobalUpdate checks for newer versions of globally installed plugins
297	// and reinstalls any that are outdated (or all if --force). It operates
298	// exclusively on the global plugin tree (${XDG_DATA_HOME}/ddx/global/) and
299	// never touches the project tree.
300	func performGlobalUpdate(opts *UpdateOptions) (*UpdateResult, error) {
301		state, err := registry.LoadGlobalState()
302		if err != nil || len(state.Installed) == 0 {
303			return &UpdateResult{Success: true, Message: "No globally installed packages."}, nil
304		}
305	
306		reg := registry.BuiltinRegistry()
307		home, err := os.UserHomeDir()
308		if err != nil {
309			return nil, fmt.Errorf("getting home dir: %w", err)
310		}
311	
312		var updated []string
313		for _, entry := range state.Installed {
314			if opts.Resource != "" && entry.Name != opts.Resource {
315				continue
316			}
317			pkg, err := reg.Find(entry.Name)
318			if err != nil {
319				continue
320			}
321	
322			latestVersion := pkg.Version
323			if release, err := update.FetchLatestReleaseForRepo(pkg.Source); err == nil {
324				latestVersion = strings.TrimPrefix(release.TagName, "v")
325			}
326	
327			if !opts.Force && entry.Version == latestVersion {
328				continue
329			}
330	
331			installPkg := *pkg
332			installPkg.Version = latestVersion
333			adjustedPkg := adjustInstallTargets(&installPkg, entry.Name,
334				filepath.Join(home, ".agents", "skills"),
335				filepath.Join(home, ".claude", "skills"))
336	
337			newEntry, err := registry.InstallPackage(adjustedPkg, ddxroot.GlobalDir())
338			if err != nil {
339				return nil, fmt.Errorf("updating global %s: %w", entry.Name, err)
340			}
341			state.AddOrUpdate(newEntry)
342			updated = append(updated, entry.Name+" "+entry.Version+" → "+latestVersion)
343		}
344	
345		if err := registry.SaveGlobalState(state); err != nil {
346			return nil, fmt.Errorf("saving global state: %w", err)
347		}
348	
349		if len(updated) == 0 {
350			return &UpdateResult{Success: true, Message: "Global packages are up to date."}, nil
351		}
352		return &UpdateResult{
353			Success:      true,
354			Message:      "Updated globally: " + strings.Join(updated, ", "),
355			UpdatedFiles: updated,
356		}, nil
357	}
