983	func installedEntryRootCandidate(entry registry.InstalledEntry) string {
984		if len(entry.Files) > 0 && strings.TrimSpace(entry.Files[0]) != "" {
985			return entry.Files[0]
986		}
987		return strings.TrimSpace(entry.Source)
988	}
