1218			return nil
1219		}
1220	
1221		promptPath := cfg.GetMetaPrompt()
1222		if promptPath == "" {
1223			// Meta-prompt disabled - not an issue
1224			return nil
1225		}
1226	
1227		injector := metaprompt.NewMetaPromptInjectorWithPaths(
1228			"CLAUDE.md",
1229			cfg.Library.Path,
1230			workingDir,
1231		)
1232	
1233		inSync, err := injector.IsInSync()
1234		if err != nil {
1235			// Could not check (file missing, etc) - not a critical issue
1236			return nil
1237		}
1238	
1239		if !inSync {
1240			return fmt.Errorf("meta-prompt is out of sync with library")
1241		}
1242	
1243		return nil
1244	}
