319	// TestCheckPackageJSONLocations_StaleNodeModules detects node_modules older than bun.lock.
320	func TestCheckPackageJSONLocations_StaleNodeModules(t *testing.T) {
321		workDir := t.TempDir()
322	
323		// Create package.json, node_modules, then a newer bun.lock.
324		if err := os.WriteFile(filepath.Join(workDir, "package.json"), []byte(`{}`), 0o644); err != nil {
325			t.Fatalf("write package.json: %v", err)
326		}
327		if err := os.MkdirAll(filepath.Join(workDir, "node_modules"), 0o755); err != nil {
328			t.Fatalf("mkdir node_modules: %v", err)
329		}
330	
331		// Write bun.lock after node_modules so it has a newer mtime.
332		if err := os.WriteFile(filepath.Join(workDir, "bun.lock"), []byte(`lockfileVersion: 0`), 0o644); err != nil {
333			t.Fatalf("write bun.lock: %v", err)
334		}
335		// Backdate node_modules to ensure bun.lock is strictly newer.
336		past := filepath.Join(workDir, "node_modules")
337		info, _ := os.Stat(past)
338		lockInfo, _ := os.Stat(filepath.Join(workDir, "bun.lock"))
339		if !lockInfo.ModTime().After(info.ModTime()) {
340			// Force the difference by touching bun.lock again.
341			now := lockInfo.ModTime().Add(2 * 1e9) // +2s
342			if err := os.Chtimes(filepath.Join(workDir, "bun.lock"), now, now); err != nil {
343				t.Fatalf("chtimes bun.lock: %v", err)
344			}
345		}
346	
347		issues := checkPackageJSONLocations(workDir)
348		if len(issues) != 1 {
349			t.Fatalf("expected 1 issue, got %d: %v", len(issues), issues)
350		}
351		if issues[0].Type != "node_modules_stale" {
352			t.Errorf("expected type node_modules_stale, got %s", issues[0].Type)
353		}
354	}
