70	// Path returns the DDx state root for projectRoot.
71	//
72	// When the project already has an in-tree `.ddx/`, that remains authoritative.
73	// Otherwise DDx falls back to an XDG-scoped convention root derived from the
74	// project's canonical git remote, or a deterministic local identity.
75	func Path(ctx context.Context, projectRoot string) string {
76		inTree := InTree(projectRoot)
77		if info, err := os.Stat(inTree); err == nil && info.IsDir() {
78			return inTree
79		}
80		root := filepath.Join(projectsRoot(), projectIdentity(ctx, projectRoot))
81		_ = bootstrapConventionRoot(ctx, projectRoot, root)
82		return root
83	}
