94	func xdgDataHome() string {
95		if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
96			return xdg
97		}
98		home, err := os.UserHomeDir()
99		if err != nil {
100			return filepath.Join(os.TempDir(), "ddx-xdg")
101		}
102		return filepath.Join(home, ".local", "share")
103	}
