133	func matchesQuery(pkg Package, query string) bool {
134		if strings.Contains(strings.ToLower(pkg.Name), query) {
135			return true
136		}
137		if strings.Contains(strings.ToLower(pkg.Description), query) {
138			return true
139		}
140		if strings.Contains(strings.ToLower(string(pkg.Type)), query) {
141			return true
142		}
143		for _, kw := range pkg.Keywords {
144			if strings.Contains(strings.ToLower(kw), query) {
145				return true
146			}
147		}
148		return false
