// TestUpdateGlobal_UpdatesGlobalNotProject asserts that ddx update --global
// updates only the global plugin tree and does not touch the project-local
// .agents/skills/ directory [AC1].
func TestUpdateGlobal_UpdatesGlobalNotProject(t *testing.T) {
	homeDir := t.TempDir()
	xdgDir := filepath.Join(homeDir, "xdg")
	t.Setenv("HOME", homeDir)
	t.Setenv("XDG_DATA_HOME", xdgDir)

	projectDir := t.TempDir()
	factory := NewCommandFactory(projectDir)
	c := factory.NewRootCommand()
	c.SetArgs([]string{"update", "--global"})

	var buf bytes.Buffer
	c.SetOut(&buf)
	c.SetErr(&buf)

	require.NoError(t, c.Execute())
	output := buf.String()

	// --global must not refresh project-local skills (refreshShippedSkills is not called)
	_, statErr := os.Stat(filepath.Join(projectDir, ".agents", "skills", "ddx"))
	assert.True(t, os.IsNotExist(statErr),
		"--global update must not create .agents/skills/ddx in the project dir")

	// Output confirms the global branch was taken (empty global state message)
	assert.Contains(t, output, "globally installed",
		"output should indicate the global branch was executed; got: %q", output)
}

// TestUpdate_RespectsConventionVsInTreeMode asserts that ddx update (no flag)
// refreshes the shipped skills in the project directory regardless of whether
// the project has an in-tree .ddx/ directory (in-tree mode) or not (convention
// mode) [AC2].
func TestUpdate_RespectsConventionVsInTreeMode(t *testing.T) {
	runUpdate := func(t *testing.T, projectDir string) (string, error) {
		t.Helper()
		factory := NewCommandFactory(projectDir)
		c := factory.NewRootCommand()
		c.SetArgs([]string{"update"})
		var buf bytes.Buffer
		c.SetOut(&buf)
		c.SetErr(&buf)
		return buf.String(), c.Execute()
	}

	t.Run("in-tree mode", func(t *testing.T) {
		homeDir := t.TempDir()
		t.Setenv("HOME", homeDir)

		projectDir := t.TempDir()
		require.NoError(t, os.MkdirAll(filepath.Join(projectDir, ddxroot.DirName), 0o755))

		output, err := runUpdate(t, projectDir)
		require.NoError(t, err)
		assert.Contains(t, output, "Shipped skills refreshed",
			"in-tree mode: expected skills refresh confirmation; got: %q", output)
		_, statErr := os.Stat(filepath.Join(projectDir, ".agents", "skills", "ddx"))
		assert.NoError(t, statErr,
			"in-tree mode: .agents/skills/ddx should exist after update")
	})

	t.Run("convention mode", func(t *testing.T) {
		homeDir := t.TempDir()
		xdgDir := filepath.Join(homeDir, "xdg")
		t.Setenv("HOME", homeDir)
		t.Setenv("XDG_DATA_HOME", xdgDir)

		// No in-tree .ddx/ — update uses convention-mode XDG project path.
		projectDir := t.TempDir()

		output, err := runUpdate(t, projectDir)
		require.NoError(t, err)
		assert.Contains(t, output, "Shipped skills refreshed",
			"convention mode: expected skills refresh confirmation; got: %q", output)
		_, statErr := os.Stat(filepath.Join(projectDir, ".agents", "skills", "ddx"))
		assert.NoError(t, statErr,
			"convention mode: .agents/skills/ddx should exist after update")
	})
}

